[
  {
    "id": "direct_pass",
    "label": "直接传递",
    "use_when": "上游某个输出可以不转换地满足下游同名或明确引用的输入。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "relay_mappings must map source_output to target_input with resolver direct.",
    "missing_behavior": "block when the selected source output is missing or empty."
  },
  {
    "id": "extract_field",
    "label": "字段提取",
    "use_when": "用户说明或真实 artifact schema 明确指出要从 JSON/object/file 中提取某个字段。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "relay_mappings must include source_output, target_input, resolver json_path or an explicit extractor description.",
    "missing_behavior": "block unless the user explicitly provides a fallback."
  },
  {
    "id": "summarize_to_message",
    "label": "摘要成消息",
    "use_when": "下游需要 message/summary，用户要求把长文本、报告或多文件压缩成通知/摘要。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "relay_mappings should select the source file/artifact and describe the summary goal.",
    "missing_behavior": "block when all selected source artifacts are missing."
  },
  {
    "id": "send_artifact_content",
    "label": "发送产物内容",
    "use_when": "用户要求把某个上游产物直接发送、展示或交给通知类节点。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "relay_mappings should select the artifact and target message/content/payload input.",
    "missing_behavior": "block when the selected artifact is missing."
  },
  {
    "id": "generated_message",
    "label": "生成运行时文本",
    "use_when": "用户要求发送当前日期、固定文案、运行状态等不依赖上游业务产物的文本。",
    "uses_upstream_artifact": false,
    "resolved_handoff": "use source_output runtime and resolver generated; explain what text is generated.",
    "missing_behavior": "block only if required runtime context is unavailable."
  },
  {
    "id": "aggregate_files",
    "label": "聚合多文件",
    "use_when": "下游需要 sources/reports/files/documents，且一个或多个上游文件要合并为输入集合。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "relay_mappings should list selected file outputs and target collection input.",
    "missing_behavior": "block when required files are missing; optional files may warn."
  },
  {
    "id": "pass_directory",
    "label": "传递目录",
    "use_when": "下游明确消费目录或文件夹，而不是单个文件或字符串。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "relay_mappings should map directory output to directory input.",
    "missing_behavior": "block when the directory is missing."
  },
  {
    "id": "optional_context",
    "label": "可选上下文",
    "use_when": "上游产物只作为补充上下文，不应该成为下游主输入。",
    "uses_upstream_artifact": true,
    "resolved_handoff": "place selected artifact under supporting context; do not satisfy required input with it.",
    "missing_behavior": "warn, do not block, unless it is explicitly marked required."
  },
  {
    "id": "cannot_infer",
    "label": "无法推断",
    "use_when": "缺少用户意图、上下游语义不对应、或无法判断要传什么/怎么转换。",
    "uses_upstream_artifact": false,
    "resolved_handoff": "do not produce relay_mappings; ask for a concrete edge_handoff_instruction.",
    "missing_behavior": "needs_instruction."
  }
]

